INSERT INTO `v1_a308c45f7c8dfb22f9bd3cb7260ce8ffc60d2568830753999ccc00693f69ddd6` VALUES (1012, "イベントボスには非常に高い「Total HP」が設定されております。\n「Total HP」は、皆さまがバトル中に与えたダメージの分だけ減らせる\nのだとか。豪華報酬を目指し、力を合わせて討伐いたしましょう。", 2, 1, 1);
INSERT INTO `v1_a308c45f7c8dfb22f9bd3cb7260ce8ffc60d2568830753999ccc00693f69ddd6` VALUES (1013, "ボスバトルは、イベント期間中に配布される「討伐チケット」を消費して\n挑戦できます。また、難易度は「ボス詳細」から変更できますよ。\n討伐を達成した難易度はスキップも行えるので、活用してくださいまし。", 3, 1, 1);
INSERT INTO `v1_a308c45f7c8dfb22f9bd3cb7260ce8ffc60d2568830753999ccc00693f69ddd6` VALUES (1021, "報酬交換では「討伐報酬券」と様々なアイテムを交換できます。\n目玉となるリセット対象報酬を引くことで、より多くのアイテムが\n獲得できる次のラインナップへと進めるそうです。", 4, 2, 1);
